A quick sketch which serves my purposes;

```python
from schematics.models import Model


class AdapterModel(Model):

    def __init__(self, raw_data=None, adapter: 'BaseAdapter'=None, *args, **kwargs):
        if adapter is not None:
            raw_data = adapter(self).to_raw_data(raw_data)

        super(AdapterModel, self).__init__(raw_data, *args, **kwargs)

    def to_adaptation(self, adapter):
        return adapter(self).from_model()


class BaseAdapter(object):

    def __init__(self, model: AdapterModel):
        self.model = model


class Product(AdapterModel):
    ...
    ...


    class LegacyAdapter(BaseAdapter):

        def to_raw_data(self, obj: dict) -> dict:
            first_name, last_name = obj['full_name'].split(' ')
            return dict(first_name=first_name, last_name=last_name)

        def from_model(self) -> dict:
            return dict(full_name='%s %s' % (self.model.first_name, self.model.last_name))

```

